class Solution:
    def maximumScore(self, nums, k):
        n = len(nums)
        best = 0
        for i in range(k, -1, -1):
            mn = nums[i]
            for j in range(i, n):
                if nums[j] < mn:
                    mn = nums[j]
                if j >= k:
                    score = mn * (j - i + 1)
                    if score > best:
                        best = score
        return best

