var maximumScore = function(nums, k) {
    const n = nums.length;
    let left = k, right = k, mn = nums[k], best = mn;
    while (left > 0 || right < n - 1) {
        const lv = left > 0 ? nums[left - 1] : -1;
        const rv = right < n - 1 ? nums[right + 1] : -1;
        if (lv >= rv) {
            left--;
            if (nums[left] < mn) mn = nums[left];
        } else {
            right++;
            if (nums[right] < mn) mn = nums[right];
        }
        const score = mn * (right - left + 1);
        if (score > best) best = score;
    }
    return best;
};
